class TestGovernorStaleAlert(unittest.TestCase):
    def test_detects_stale_red_day(self):
        import datetime
        yesterday = (datetime.date.today() - datetime.timedelta(days=1)).isoformat()
        state = {"daily_peak": {"date": yesterday, "verdict": "RED_DAY_AFTER_GREEN"}}
        fired, reason = heuristic_governor_stale_state_alert(state)
        self.assertTrue(fired)
        self.assertIn("RED_DAY_AFTER_GREEN", reason)
    def test_no_alert_same_day(self):
        import datetime
        today = datetime.date.today().isoformat()
        state = {"daily_peak": {"date": today, "verdict": "RED_DAY_AFTER_GREEN"}}
        fired, _ = heuristic_governor_stale_state_alert(state)
        self.assertFalse(fired)
    def test_no_alert_normal_flat_state(self):
        import datetime
        yesterday = (datetime.date.today() - datetime.timedelta(days=1)).isoformat()
        state = {"daily_peak": {"date": yesterday, "verdict": "FLAT"}}
        fired, _ = heuristic_governor_stale_state_alert(state)
        self.assertFalse(fired)
    def test_no_alert_empty_state(self):
        fired, _ = heuristic_governor_stale_state_alert({})
        self.assertFalse(fired)
    def test_detects_stale_defend_day(self):
        import datetime
        yesterday = (datetime.date.today() - datetime.timedelta(days=1)).isoformat()
        state = {"daily_peak": {"date": yesterday, "verdict": "DEFEND_DAY"}}
        fired, reason = heuristic_governor_stale_state_alert(state)
        self.assertTrue(fired)
        self.assertIn("DEFEND_DAY", reason)
